# Protecting Against SQL Injection Attacks

## Key Principles

1. **Never concatenate user input directly into SQL queries**
2. **Always use parameterized queries/prepared statements**
3. **Apply principle of least privilege to database users**
4. **Validate and sanitize all inputs**

## Parameterized Query Examples

### Python (with psycopg2 - PostgreSQL)

```python
import psycopg2

# ✅ SAFE - Parameterized query
def get_user_safe(username):
    conn = psycopg2.connect("dbname=mydb user=myuser")
    cursor = conn.cursor()

    # Use %s placeholders, pass values as tuple
    cursor.execute(
        "SELECT * FROM users WHERE username = %s",
        (username,)
    )
    result = cursor.fetchall()
    cursor.close()
    conn.close()
    return result

# ❌ UNSAFE - String concatenation
def get_user_unsafe(username):
    cursor.execute(
        f"SELECT * FROM users WHERE username = '{username}'"
    )
```

### Python (with SQLite3)

```python
import sqlite3

# ✅ SAFE - Parameterized query
def insert_user(username, email):
    conn = sqlite3.connect('database.db')
    cursor = conn.cursor()

    cursor.execute(
        "INSERT INTO users (username, email) VALUES (?, ?)",
        (username, email)
    )
    conn.commit()
    conn.close()
```

### Python (with MySQL - mysql-connector)

```python
import mysql.connector

# ✅ SAFE - Parameterized query
def update_user(user_id, new_email):
    conn = mysql.connector.connect(
        host="localhost",
        user="myuser",
        password="mypass",
        database="mydb"
    )
    cursor = conn.cursor()

    cursor.execute(
        "UPDATE users SET email = %s WHERE id = %s",
        (new_email, user_id)
    )
    conn.commit()
    cursor.close()
    conn.close()
```

### Node.js (with pg - PostgreSQL)

```javascript
const { Pool } = require('pg');
const pool = new Pool();

// ✅ SAFE - Parameterized query
async function getUserSafe(username) {
    const result = await pool.query(
        'SELECT * FROM users WHERE username = $1',
        [username]
    );
    return result.rows;
}

// ❌ UNSAFE
async function getUserUnsafe(username) {
    const result = await pool.query(
        `SELECT * FROM users WHERE username = '${username}'`
    );
}
```

### Node.js (with mysql2)

```javascript
const mysql = require('mysql2/promise');

// ✅ SAFE - Parameterized query
async function createUser(username, email) {
    const connection = await mysql.createConnection({
        host: 'localhost',
        user: 'root',
        database: 'mydb'
    });

    const [rows] = await connection.execute(
        'INSERT INTO users (username, email) VALUES (?, ?)',
        [username, email]
    );

    await connection.end();
    return rows;
}
```

### PHP (with PDO)

```php
<?php
// ✅ SAFE - Prepared statements
function getUser($username) {
    $pdo = new PDO('mysql:host=localhost;dbname=mydb', 'user', 'pass');

    $stmt = $pdo->prepare('SELECT * FROM users WHERE username = :username');
    $stmt->execute(['username' => $username]);

    return $stmt->fetchAll();
}

